        },
        [ordered]@{
          Name = "Installer un couvercle avec peu d'emplacements"
          Text = "Commence avec deux à quatre pots filet seulement pour garder un système lisible, simple à déplacer et simple à nettoyer."
        },
        [ordered]@{
          Name = "Préparer une solution nutritive mesurée"
          Text = "Utilise une eau propre et des nutriments hydroponiques en suivant le dosage prévu, sans chercher à accélérer la pousse."
        },
        [ordered]@{
