  $overrides["basilic-hydroponie-interieur"] = [ordered]@{
    Title = "Basilic hydroponie intérieur : facile, rapide et très utile"
    CardTitle = "Basilic en hydroponie intérieure"
    SeoTitle = "Basilic hydroponie intérieur"
